// Crystal Growth
// Adapted from GenerativeArtGallery / artwork2

let cg = [];
let cgPrevHue = '';

function cgSpawn(fMin, fMax, hStr, szBase) {
  let hue = hStr === 'cool' ? 180 + Math.random() * 60 :
            hStr === 'warm' ? Math.random() * 55 :
            hStr === 'jewel' ? 260 + Math.random() * 60 : Math.random() * 360;
  let facets = Math.floor(Math.random() * (fMax - fMin + 1)) + fMin;
  let angles = [];
  for (let i = 0; i < facets; i++) angles.push(Math.random() * Math.PI * 2);
  angles.sort(function(a, b) { return a - b; });
  return {
    x: Math.random() * 400, y: Math.random() * 400,
    size: 15 + Math.random() * 20,
    growthRate: 0.18 + Math.random() * 0.4,
    maxSize: szBase * (0.5 + Math.random() * 0.7),
    hue: hue, angles: angles
  };
}

p.setup = function() {
  p.createCanvas(400, 400);
  p.colorMode(p.HSB, 360, 100, 100, 100);
  p.frameRate(30);
  p.background(220, 30, 10);
  for (let i = 0; i < 5; i++) cg.push(cgSpawn(5, 7, 'cool', 120));
};

p.draw = function() {
  let maxStr  = p.getSynthVar('max_crystals') || 'medium';
  let facetStr = p.getSynthVar('facet_count') || 'balanced';
  let speedStr = p.getSynthVar('growth_speed') || 'medium';
  let hueStr   = p.getSynthVar('hue_range') || 'cool';
  let sizeStr  = p.getSynthVar('max_size') || 'medium';

  let maxC  = maxStr === 'few' ? 8 : maxStr === 'medium' ? 18 : 36;
  let fMin  = facetStr === 'angular' ? 4 : facetStr === 'balanced' ? 5 : 6;
  let fMax  = facetStr === 'angular' ? 5 : facetStr === 'balanced' ? 7 : 10;
  let gMult = speedStr === 'slow' ? 0.4 : speedStr === 'medium' ? 1 : 2.2;
  let szBase = sizeStr === 'small' ? 75 : sizeStr === 'medium' ? 135 : 210;

  p.background(220, 30, 10, 8);

  if (cg.length < maxC && p.frameCount % 42 === 0) {
    cg.push(cgSpawn(fMin, fMax, hueStr, szBase));
  }
  if (cg.length > maxC) cg.splice(0, cg.length - maxC);

  cg.forEach(function(c) {
    if (c.size < c.maxSize) c.size += c.growthRate * gMult;

    for (let layer = 2; layer >= 0; layer--) {
      let shade = layer / 2;
      let off = layer * 2.5;
      p.push();
      p.translate(c.x + off, c.y + off);
      p.fill(c.hue, 38 + shade * 42, 48 + shade * 42, 90);
      p.stroke(c.hue, 28, 30, 35);
      p.strokeWeight(0.7);
      p.beginShape();
      c.angles.forEach(function(a) {
        let r = c.size * (0.78 + 0.22 * Math.sin(a * 3 + shade));
        p.vertex(Math.cos(a) * r, Math.sin(a) * r);
      });
      p.endShape(p.CLOSE);
      p.pop();
    }
  });
};
